export type GameEvent =
  | { type: 'FILE_DROPPED'; file: File }
  | { type: 'SONG_LOADED'; noteGroups: NoteGroup[] }
  | { type: 'LOAD_FAILED'; error: string }
  | { type: 'NOTE_PRESSED'; cellId: string; midiNote: number }
  | { type: 'GAME_RESET' }
  | { type: 'GAME_RESTART' }
  | { type: 'TUNING_WARN_ACK' };
