const ROW_STAGGER: Record<number, number> = { 0: 0, 1: 1, 2: 2, 3: 3 };

function iqToDCompose(iqX: number, iqY: number): KeyCoordinate {
  const ex = iqX + (ROW_STAGGER[iqY] ?? 0);
  return [2 * ex - iqY - 12, -ex + 7];
}
